const slugify = (value = '') => String(value)
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9\u4e00-\u9fa5]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .toLowerCase();

const shouldWriteToVault = Boolean($json.should_write_to_vault);
const existingVaultPath = String($json.vault_path || '').trim();
const existingWriteStatus = String($json.vault_write_status || $json.vault_write || '').trim();
const canonicalObsidianInboxDir = String($json.obsidianInboxDir || '').trim();
const legacyObsidianInboxDir = String($json.obsidian_inbox_dir || '').trim();
if (
  canonicalObsidianInboxDir &&
  legacyObsidianInboxDir &&
  canonicalObsidianInboxDir !== legacyObsidianInboxDir
) {
  throw new Error('05_common_vault_writer received conflicting obsidianInboxDir and obsidian_inbox_dir; normalize through 00_common_normalize_text_object before writing');
}
const obsidianInboxDir = canonicalObsidianInboxDir
  || legacyObsidianInboxDir
  || String($env.OBSIDIAN_INBOX_DIR || '00_Inbox/AI_Information_Processor').trim()
  || '00_Inbox/AI_Information_Processor';
const workflowLabel = String($json.workflow_label || $json.workflow_name || $json.workflow || 'ai-information-processor-mainline').trim() || 'ai-information-processor-mainline';

let fileBaseName = '';
let relativeFilePath = existingVaultPath;
const itemId = String($json.item_id || '').trim();
const title = String($json.title || '').trim();
if (itemId && title) {
  const dateForFile = new Date($json.published_at || Date.now());
  const safeDate = Number.isNaN(dateForFile.getTime()) ? new Date() : dateForFile;
  const yyyy = safeDate.getUTCFullYear();
  const mm = String(safeDate.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(safeDate.getUTCDate()).padStart(2, '0');
  const datePrefix = `${yyyy}-${mm}-${dd}`;
  const sourceType = slugify($json.source_type || 'item') || 'item';
  const itemIdShort = itemId.slice(0, 10) || 'unknown';
  const titleSlug = slugify(title).slice(0, 80) || 'untitled';
  fileBaseName = `${datePrefix}_${sourceType}_${itemIdShort}_${titleSlug}`;
  relativeFilePath = `${obsidianInboxDir}/${fileBaseName}.md`;
}

if (shouldWriteToVault && !relativeFilePath) {
  throw new Error('05_common_vault_writer requires item_id/title/published_at to build a deterministic vault path');
}

const vaultWriteStatus = shouldWriteToVault ? 'pending' : (existingWriteStatus || 'skipped');

return {
  json: {
    ...$json,
    obsidianInboxDir,
    workflow_label: workflowLabel,
    fileBaseName,
    relativeFilePath,
    vault_path: relativeFilePath,
    vault_write_status: vaultWriteStatus,
    vault_write: vaultWriteStatus
  }
};

const yamlEscape = (value = '') => String(value)
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"');

const yamlBlock = (key, value = '') => {
  const normalized = String(value || '').replace(/\r\n/g, '\n').trim();
  if (!normalized) {
    return '';
  }
  const indented = normalized
    .split('\n')
    .map((line) => `  ${line}`)
    .join('\n');
  return `${key}: |-\n${indented}\n`;
};

const yamlScalar = (value) => {
  if (typeof value === 'number') {
    return Number.isInteger(value) ? String(value) : String(Number(value));
  }
  if (typeof value === 'boolean') {
    return value ? 'true' : 'false';
  }
  return `"${yamlEscape(value)}"`;
};

const yamlMapBlock = (key, value) => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return '';
  }
  const entries = Object.entries(value)
    .filter(([, entryValue]) => entryValue !== undefined && entryValue !== null && !(typeof entryValue === 'string' && !entryValue.trim()))
    .map(([entryKey, entryValue]) => `  ${entryKey}: ${yamlScalar(entryValue)}`)
    .join('\n');
  return entries ? `${key}:\n${entries}\n` : '';
};

const normalizeMultiline = (value = '') => String(value || '')
  .replace(/\r\n/g, '\n')
  .replace(/\u0000/g, '')
  .trim();

const normalizeSingleLine = (value = '') => normalizeMultiline(value)
  .replace(/\s+/g, ' ')
  .trim();

const truncateText = (value = '', maxChars = 140, suffix = '...') => {
  const normalized = normalizeSingleLine(value);
  if (!normalized) {
    return '';
  }
  if (normalized.length <= maxChars) {
    return normalized;
  }
  const sliceLength = Math.max(0, maxChars - suffix.length);
  return `${normalized.slice(0, sliceLength).trim()}${suffix}`;
};

const extractQuickTake = (value = '') => {
  const normalized = normalizeSingleLine(value);
  if (!normalized) {
    return '';
  }
  const sentenceMatch = normalized.match(/^.{1,140}?[。！？.!?](?=\s|$)/);
  if (sentenceMatch?.[0]) {
    return sentenceMatch[0].trim();
  }
  return truncateText(normalized, 140);
};

const toIsoDate = (value) => {
  const parsed = new Date(value || Date.now());
  if (Number.isNaN(parsed.getTime())) {
    return '';
  }
  return parsed.toISOString().slice(0, 10);
};

const toSafeNumber = (value, fallback = 0) => {
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? numericValue : fallback;
};

const toIntDisplay = (value, fallback = 'n/a') => {
  const numericValue = Math.round(Number(value));
  return Number.isFinite(numericValue) ? String(numericValue) : fallback;
};

const cloneJson = (value) => {
  if (value === undefined) {
    return undefined;
  }
  if (value === null) {
    return null;
  }
  return JSON.parse(JSON.stringify(value));
};

const fileBaseName = String($json.fileBaseName || '').trim();
const relativeFilePath = String($json.relativeFilePath || '').trim();
if (!fileBaseName || !relativeFilePath) {
  throw new Error('05_common_vault_writer is missing fileBaseName/relativeFilePath before Markdown generation');
}

const lastSlashIndex = relativeFilePath.lastIndexOf('/');
const relativeDir = lastSlashIndex >= 0 ? relativeFilePath.slice(0, lastSlashIndex) : '';
const mediaType = String($json.media_type || '').trim().toLowerCase();
const sourceType = String($json.source_type || '').trim().toLowerCase();
const rawKind = ['audio', 'video'].includes(mediaType) || ['podcast', 'transcript', 'audio'].includes(sourceType)
  ? 'transcript'
  : 'raw';
const rawHeading = rawKind === 'transcript' ? '原始转写' : '原始文本';
const rawFileName = `${fileBaseName}__${rawKind}.md`;
const auditFileName = `${fileBaseName}__audit.json`;
const rawRelativePath = `${relativeDir}/_raw/${rawFileName}`;
const auditRelativePath = `${relativeDir}/_audit/${auditFileName}`;
const rawRelativeLink = `_raw/${rawFileName}`;
const auditRelativeLink = `_audit/${auditFileName}`;
const rawParentLink = `../${fileBaseName}.md`;

const canonicalUrl = String($json.canonical_url || '').trim();
const workflowLabel = String($json.workflow_label || 'ai-information-processor-mainline').trim() || 'ai-information-processor-mainline';
const summary = normalizeMultiline($json.summary || '');
const reason = normalizeMultiline($json.reason || '');
const contentText = normalizeMultiline($json.content_text || '');
const upstreamSummary = normalizeMultiline($json.upstream_summary || '');
const quickTake = extractQuickTake(summary) || extractQuickTake(reason) || truncateText(contentText, 140) || '暂无。';
const showSummarySection = Boolean(summary) && normalizeSingleLine(summary) !== normalizeSingleLine(quickTake);
const dedupeAction = String($json.dedupe_action || 'full_push').trim() || 'full_push';
const notificationMode = String($json.notification_mode || '').trim();
const notificationDisplay = notificationMode || 'silent';
const matchedPayload = $json.matched_payload && typeof $json.matched_payload === 'object' ? $json.matched_payload : null;
const matchedScore = toSafeNumber($json.matched_score, NaN);
const matchedTitle = matchedPayload ? normalizeSingleLine(matchedPayload.title || '') : '';
const matchedItemId = matchedPayload ? normalizeSingleLine(matchedPayload.item_id || '') : '';
const matchedCanonicalUrl = matchedPayload ? normalizeSingleLine(matchedPayload.canonical_url || '') : '';
const tags = Array.isArray($json.tags) && $json.tags.length
  ? $json.tags.filter(Boolean)
  : ['inbox', 'ai-information-processor'];
const normalizedTags = [...new Set([...tags, `dedupe-${dedupeAction}`].filter(Boolean))];
const tagLines = normalizedTags.map((tag) => `  - ${tag}`).join('\n');
const aiScore = $json.ai_score && typeof $json.ai_score === 'object' ? $json.ai_score : null;
const keepScoreText = toIntDisplay(aiScore?.keep_score, toIntDisplay(toSafeNumber($json.score, 0) * 100));
const referenceScoreText = toIntDisplay(aiScore?.reference_score);
const actionScoreText = toIntDisplay(aiScore?.action_score);
const notifyScoreText = toIntDisplay(aiScore?.notify_score);
const decisionHint = normalizeSingleLine(aiScore?.decision_hint || '');
const decisionDisplay = decisionHint || normalizeSingleLine($json.status || 'raw') || 'raw';
const sourceLine = [
  mediaType === 'audio' ? '播客' : mediaType === 'video' ? '视频' : mediaType === 'text' ? '文章' : normalizeSingleLine($json.media_type || ''),
  normalizeSingleLine($json.author || $json.source_name || ''),
  toIsoDate($json.published_at)
].filter(Boolean).join(' · ');
const auditLine = [
  normalizeSingleLine($json.ai_meta?.rubric_version || ''),
  normalizeSingleLine($json.ai_meta?.model || ''),
  Number.isFinite(Number($json.ai_meta?.input_chars)) ? `input_chars ${Math.round(Number($json.ai_meta.input_chars))}` : ''
].filter(Boolean).join(' · ');
const relatedLines = matchedPayload ? [
  matchedTitle ? `- 相似对象：${matchedTitle}` : '',
  Number.isFinite(matchedScore) && matchedScore > 0 ? `- matched_score: ${matchedScore.toFixed(4)}` : '',
  matchedCanonicalUrl ? `- 原始链接：${matchedCanonicalUrl}` : '',
  '- 关系：主题上存在重叠，详细判定见审计 sidecar。'
].filter(Boolean).join('\n') : '';
const sourceHostLine = $json.source_host ? `source_host: \"${yamlEscape($json.source_host)}\"\n` : '';
const originalIdLine = $json.original_id ? `original_id: \"${yamlEscape($json.original_id)}\"\n` : '';
const enrichedAtLine = $json.enriched_at ? `enriched_at: \"${yamlEscape($json.enriched_at)}\"\n` : '';
const notificationModeLine = notificationMode ? `notification_mode: \"${yamlEscape(notificationMode)}\"\n` : '';
const matchedScoreLine = Number.isFinite(matchedScore) && matchedScore > 0 ? `matched_score: ${matchedScore}\n` : '';
const matchedItemIdLine = matchedItemId ? `matched_item_id: \"${yamlEscape(matchedItemId)}\"\n` : '';
const matchedCanonicalUrlLine = matchedCanonicalUrl ? `matched_canonical_url: \"${yamlEscape(matchedCanonicalUrl)}\"\n` : '';
const matchedSameItemLine = $json.matched_same_item ? 'matched_same_item: true\n' : '';
const scoreScale = Math.round(toSafeNumber($json.score_scale, 100));
const scoreScaleLine = Number.isFinite(scoreScale) ? `score_scale: ${scoreScale}\n` : '';
const summaryLine = yamlBlock('summary', summary);
const reasonLine = yamlBlock('reason', reason);
const aiScoreLine = yamlMapBlock('ai_score', $json.ai_score);
const scoreDimensionsLine = yamlMapBlock('score_dimensions', $json.score_dimensions);
const aiMetaLine = yamlMapBlock('ai_meta', $json.ai_meta);
const viewVersionLine = 'view_version: \"layered_v1\"\n';
const rawVaultPathLine = `raw_vault_path: \"${yamlEscape(rawRelativePath)}\"\n`;
const auditVaultPathLine = `audit_vault_path: \"${yamlEscape(auditRelativePath)}\"\n`;
const sourceNameDisplay = normalizeSingleLine($json.source_name || 'unknown-source');
const originalMaterialLines = [
  `- 原始材料：[${rawFileName}](${rawRelativeLink})`,
  `- LLM 审计：[${auditFileName}](${auditRelativeLink})`,
  canonicalUrl ? `- 原始链接：${canonicalUrl}` : ''
].filter(Boolean).join('\n');
const markdown = `---\ntitle: \"${yamlEscape($json.title)}\"\nitem_id: \"${yamlEscape($json.item_id)}\"\nsource_type: \"${yamlEscape($json.source_type)}\"\nsource_name: \"${yamlEscape($json.source_name)}\"\n${sourceHostLine}${originalIdLine}canonical_url: \"${yamlEscape(canonicalUrl)}\"\npublished_at: \"${yamlEscape($json.published_at)}\"\ningested_at: \"${yamlEscape($json.ingested_at)}\"\n${enrichedAtLine}media_type: \"${yamlEscape($json.media_type)}\"\ncontent_hash: \"${yamlEscape($json.content_hash)}\"\nworkflow: \"${yamlEscape(workflowLabel)}\"\n${viewVersionLine}${rawVaultPathLine}${auditVaultPathLine}score: ${toSafeNumber($json.score, 0)}\n${scoreScaleLine}category: \"${yamlEscape($json.category || 'pending')}\"\ndedupe_action: \"${yamlEscape(dedupeAction)}\"\nstatus: \"${yamlEscape($json.status || 'raw')}\"\n${notificationModeLine}${matchedScoreLine}${matchedItemIdLine}${matchedCanonicalUrlLine}${matchedSameItemLine}${$json.author ? `author: \"${yamlEscape($json.author)}\"\n` : ''}${summaryLine}${reasonLine}${aiScoreLine}${scoreDimensionsLine}${aiMetaLine}tags:\n${tagLines}\n---\n\n# ${$json.title}\n\n> ${sourceLine || sourceNameDisplay}\n> Keep ${keepScoreText} / Reference ${referenceScoreText} / Action ${actionScoreText} / Notify ${notifyScoreText}\n> 状态：${decisionDisplay} · 通知：${notificationDisplay}${auditLine ? `\n> 审计：${auditLine}` : ''}\n\n## 一句话判断\n\n${quickTake}\n\n${reason ? `## 为什么值得保留\n\n${reason}\n\n` : ''}${showSummarySection ? `## 内容摘要\n\n${summary}\n\n` : ''}${relatedLines ? `## 关联对象\n\n${relatedLines}\n\n` : ''}## 原始材料\n\n${originalMaterialLines}\n`;

const rawMarkdown = `---\ntitle: \"${yamlEscape($json.title)}\"\nitem_id: \"${yamlEscape($json.item_id)}\"\nparent_note: \"${yamlEscape(relativeFilePath)}\"\nsource_type: \"${yamlEscape($json.source_type)}\"\nsource_name: \"${yamlEscape($json.source_name)}\"\ncanonical_url: \"${yamlEscape(canonicalUrl)}\"\nmedia_type: \"${yamlEscape($json.media_type)}\"\nraw_kind: \"${yamlEscape(rawKind)}\"\ncontent_hash: \"${yamlEscape($json.content_hash)}\"\n---\n\n# ${rawHeading}\n\n- 主笔记：[../${fileBaseName}.md](${rawParentLink})\n${canonicalUrl ? `- 原始链接：${canonicalUrl}\n` : ''}- 字符数：${contentText.length}\n\n${contentText || 'No text content extracted from this item.'}\n`;

const compactMatchedPayload = matchedPayload ? {
  item_id: matchedItemId || undefined,
  title: matchedTitle || undefined,
  canonical_url: matchedCanonicalUrl || undefined,
  score: matchedPayload.score ?? undefined,
  category: normalizeSingleLine(matchedPayload.category || '') || undefined,
  summary: truncateText(matchedPayload.summary || '', 600),
  tags: Array.isArray(matchedPayload.tags) ? matchedPayload.tags : [],
  content_hash: normalizeSingleLine(matchedPayload.content_hash || '') || undefined
} : null;

const auditPayload = {
  version: 1,
  generated_at: new Date().toISOString(),
  item_id: normalizeSingleLine($json.item_id || ''),
  note: {
    main_vault_path: relativeFilePath,
    raw_vault_path: rawRelativePath,
    audit_vault_path: auditRelativePath
  },
  source: {
    source_type: normalizeSingleLine($json.source_type || ''),
    source_name: normalizeSingleLine($json.source_name || ''),
    source_host: normalizeSingleLine($json.source_host || ''),
    original_id: normalizeSingleLine($json.original_id || ''),
    canonical_url: canonicalUrl,
    title: normalizeSingleLine($json.title || ''),
    author: normalizeSingleLine($json.author || ''),
    published_at: normalizeSingleLine($json.published_at || ''),
    ingested_at: normalizeSingleLine($json.ingested_at || ''),
    media_type: normalizeSingleLine($json.media_type || ''),
    content_hash: normalizeSingleLine($json.content_hash || ''),
    tags: normalizedTags
  },
  scoring: {
    score: toSafeNumber($json.score, 0),
    score_scale: scoreScale,
    category: normalizeSingleLine($json.category || 'pending') || 'pending',
    summary,
    reason,
    ai_score: cloneJson($json.ai_score ?? null),
    score_dimensions: cloneJson($json.score_dimensions ?? null),
    ai_meta: cloneJson($json.ai_meta ?? null),
    status: normalizeSingleLine($json.status || ''),
    decision_hint: decisionHint || null,
    notification_mode: notificationDisplay
  },
  dedupe: {
    dedupe_action: dedupeAction,
    matched_score: Number.isFinite(matchedScore) && matchedScore > 0 ? Number(matchedScore.toFixed(8)) : null,
    matched_same_item: Boolean($json.matched_same_item),
    matched_payload: compactMatchedPayload
  },
  workflow: {
    workflow_label: workflowLabel,
    should_write_to_vault: Boolean($json.should_write_to_vault),
    should_upsert_qdrant: Boolean($json.should_upsert_qdrant),
    qdrant_operation: normalizeSingleLine($json.qdrant_operation || '') || 'pending'
  },
  input_view: {
    title: normalizeSingleLine($json.title || ''),
    source_name: sourceNameDisplay,
    source_type: normalizeSingleLine($json.source_type || ''),
    author: normalizeSingleLine($json.author || ''),
    canonical_url: canonicalUrl,
    published_at: normalizeSingleLine($json.published_at || ''),
    dedupe_action: dedupeAction,
    upstream_summary: upstreamSummary || '',
    nearest_match: compactMatchedPayload ? {
      item_id: compactMatchedPayload.item_id || '',
      title: compactMatchedPayload.title || '',
      matched_score: Number.isFinite(matchedScore) && matchedScore > 0 ? Number(matchedScore.toFixed(8)) : null,
      category: compactMatchedPayload.category || '',
      summary: compactMatchedPayload.summary || ''
    } : null,
    content_text_chars: contentText.length,
    content_text_preview: truncateText(contentText, 1500)
  }
};

return {
  json: {
    ...$json,
    vault_path: relativeFilePath,
    raw_vault_path: rawRelativePath,
    audit_vault_path: auditRelativePath,
    vault_write_status: 'pending',
    vault_write: 'pending'
  },
  binary: {
    mainNote: {
      data: Buffer.from(markdown, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: `${fileBaseName}.md`,
      fileExtension: 'md'
    },
    rawNote: {
      data: Buffer.from(rawMarkdown, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: rawFileName,
      fileExtension: 'md'
    },
    auditNote: {
      data: Buffer.from(JSON.stringify(auditPayload, null, 2), 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: auditFileName,
      fileExtension: 'json'
    }
  }
};

const vaultPath = String($json.relativeFilePath || $json.vault_path || '').trim();
const shouldUpsert = Boolean($json.should_upsert_qdrant);
return {
  json: {
    ...$json,
    vault_path: vaultPath,
    vault_write_status: 'written',
    vault_write: 'written',
    qdrant_operation: shouldUpsert ? 'pending' : 'skipped',
    qdrant_upsert_response: null
  }
};

const status = String($json.vault_write_status || $json.vault_write || '').trim() || 'skipped';
const vaultPath = String($json.relativeFilePath || $json.vault_path || '').trim();
return {
  json: {
    ...$json,
    vault_path: vaultPath,
    vault_write_status: status,
    vault_write: status,
    qdrant_operation: 'skipped',
    qdrant_upsert_response: null
  }
};

return {
  json: {
    ...$json,
    vault_path: String($json.vault_path || $json.relativeFilePath || '').trim(),
    vault_write_status: String($json.vault_write_status || $json.vault_write || 'skipped').trim() || 'skipped',
    vault_write: String($json.vault_write || $json.vault_write_status || 'skipped').trim() || 'skipped',
    qdrant_operation: String($json.qdrant_operation || 'skipped').trim() || 'skipped',
    qdrant_upsert_response: $json.qdrant_upsert_response ?? null
  }
};
